@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats Bar -->
    <div class="row mb-3">
        <div class="col">
            <div class="d-flex gap-3 p-2 bg-light rounded">
                <span><strong>Total:</strong> @FilteredTasks.Count</span>
                <span><strong>To Do:</strong> @TodoTasks.Count</span>
                <span><strong>In Progress:</strong> @InProgressTasks.Count</span>
                <span><strong>Done:</strong> @DoneTasks.Count</span>
                <span><strong>Overdue:</strong> @OverdueTasks.Count</span>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="row mb-3">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Search tasks by title..."
                   @bind="_searchText" @bind:event="oninput" />
        </div>
    </div>

    <!-- Kanban Columns -->
    <div class="row">
        @foreach (var column in _columns)
        {
            var tasks = GetTasksForColumn(column);
            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body">
                        @foreach (var task in tasks)
                        {
                            <div class="card mb-2">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="card-text mb-1"><small>@task.Assignee</small></p>
                                    <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                    <small class="ms-2">@task.DueDate.ToString("MMM dd")</small>
                                    <div class="mt-2">
                                        @if (column != "To Do")
                                        {
                                            <button class="btn btn-sm btn-outline-secondary me-1"
                                                    @onclick="() => MoveTask(task, -1)">Move Left</button>
                                        }
                                        @if (column != "Done")
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    @onclick="() => MoveTask(task, 1)">Move Right</button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_showFormForColumn == column)
                        {
                            <div class="card mb-2 border-primary">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-1"
                                           @bind="_newDueDate" />
                                    <button class="btn btn-sm btn-primary me-1"
                                            @onclick="() => SaveTask(column)">Save</button>
                                    <button class="btn btn-sm btn-secondary"
                                            @onclick="CancelAdd">Cancel</button>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-sm btn-outline-primary w-100"
                                    @onclick="() => ShowAddForm(column)">Add Task</button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> _tasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;
    private string? _showFormForColumn;

    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    private readonly string[] _columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> FilteredTasks => string.IsNullOrWhiteSpace(_searchText)
        ? _tasks
        : _tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TodoTasks => GetTasksForColumn("To Do");
    private List<TaskItem> InProgressTasks => GetTasksForColumn("In Progress");
    private List<TaskItem> DoneTasks => GetTasksForColumn("Done");
    private List<TaskItem> OverdueTasks => FilteredTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    private List<TaskItem> GetTasksForColumn(string status) =>
        FilteredTasks.Where(t => t.Status == status).ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = Array.IndexOf(_columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = _tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
                _tasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private void ShowAddForm(string column)
    {
        _showFormForColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd()
    {
        _showFormForColumn = null;
    }

    private async Task SaveTask(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle)) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // If created task status doesn't match column, move it
            if (created.Status != column)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
                created = created with { Status = column };
            }
            _tasks.Add(created);
            _showFormForColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }

    private string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

